diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index bbfed2ac2c09..299088feb23e 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -661,8 +661,13 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto TypeSize = DL.getTypeStoreSize(Ty);
     if (!TypeSize.isScalable() && Offset) {
       int64_t Size = TypeSize.getFixedValue();
-      return ConstantRange(APInt(64, *Offset, true),
-                           APInt(64, *Offset + Size, true));
+      APInt Lower(64, *Offset, true);
+      APInt Upper(64, *Offset, true);
+      bool Overflow = false;
+      Upper = Upper.sadd_ov(APInt(64, Size, true), Overflow);
+      if (Overflow)
+        return std::nullopt;
+      return ConstantRange(Lower, Upper);
     }
     return std::nullopt;
   };
@@ -672,9 +677,13 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto *ConstantLength = dyn_cast<ConstantInt>(Length);
     if (ConstantLength && Offset &&
         ConstantLength->getValue().isStrictlyPositive()) {
-      return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
+      APInt Lower(64, *Offset, true);
+      APInt Upper(64, *Offset, true);
+      bool Overflow = false;
+      Upper = Upper.sadd_ov(ConstantLength->getValue().sextOrTrunc(64), Overflow);
+      if (Overflow)
+        return std::nullopt;
+      return ConstantRange(Lower, Upper);
     }
     return std::nullopt;
   };
@@ -687,6 +696,13 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
       if (auto TypeAccessRange =
               GetTypeAccessRange(SI->getAccessType(), ArgUse.Offset))
         AccessRanges.insert(*TypeAccessRange);
+      // Only treat as unknown if we had an offset and the type is fixed-size
+      // but overflow occurred. Otherwise, it's a write with empty range.
+      else if (ArgUse.Offset) {
+        auto TypeSize = DL.getTypeStoreSize(SI->getAccessType());
+        if (!TypeSize.isScalable())
+          return {ArgumentAccessInfo::AccessType::Unknown, {}};
+      }
       return {ArgumentAccessInfo::AccessType::Write, std::move(AccessRanges)};
     }
   } else if (auto *LI = dyn_cast<LoadInst>(I)) {
@@ -705,6 +721,10 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
       if (auto AccessRange =
               GetConstantIntRange(MemSet->getLength(), ArgUse.Offset))
         AccessRanges.insert(*AccessRange);
+      // Only treat as unknown if we had an offset and the length is constant
+      // but overflow occurred. Otherwise, it's a write with empty range.
+      else if (ArgUse.Offset && isa<ConstantInt>(MemSet->getLength()))
+        return {ArgumentAccessInfo::AccessType::Unknown, {}};
       return {ArgumentAccessInfo::AccessType::Write, AccessRanges};
     }
   } else if (auto *MTI = dyn_cast<MemTransferInst>(I)) {
@@ -714,11 +734,19 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
         if (auto AccessRange =
                 GetConstantIntRange(MTI->getLength(), ArgUse.Offset))
           AccessRanges.insert(*AccessRange);
+        // Only treat as unknown if we had an offset and the length is constant
+        // but overflow occurred. Otherwise, it's a write with empty range.
+        else if (ArgUse.Offset && isa<ConstantInt>(MTI->getLength()))
+          return {ArgumentAccessInfo::AccessType::Unknown, {}};
         return {ArgumentAccessInfo::AccessType::Write, AccessRanges};
       } else if (&MTI->getOperandUse(1) == ArgUse.U) {
         if (auto AccessRange =
                 GetConstantIntRange(MTI->getLength(), ArgUse.Offset))
           return {ArgumentAccessInfo::AccessType::Read, {*AccessRange}};
+        // Only treat as unknown if we had an offset and the length is constant
+        // but overflow occurred. Otherwise, it's a read with empty range.
+        else if (ArgUse.Offset && isa<ConstantInt>(MTI->getLength()))
+          return {ArgumentAccessInfo::AccessType::Unknown, {}};
       }
     }
   } else if (auto *CB = dyn_cast<CallBase>(I)) {
@@ -735,9 +763,19 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
         ConstantRangeList AccessRanges;
         Attribute Attr = CB->getParamAttr(ArgNo, Attribute::Initializes);
         ConstantRangeList CBCRL = Attr.getValueAsConstantRangeList();
-        for (ConstantRange &CR : CBCRL)
-          AccessRanges.insert(ConstantRange(CR.getLower() + *ArgUse.Offset,
-                                            CR.getUpper() + *ArgUse.Offset));
+        bool Overflow = false;
+        for (ConstantRange &CR : CBCRL) {
+          APInt Lower = CR.getLower();
+          APInt Upper = CR.getUpper();
+          APInt Offset(64, *ArgUse.Offset, true);
+          Lower = Lower.sadd_ov(Offset, Overflow);
+          if (Overflow)
+            return {ArgumentAccessInfo::AccessType::Unknown, {}};
+          Upper = Upper.sadd_ov(Offset, Overflow);
+          if (Overflow)
+            return {ArgumentAccessInfo::AccessType::Unknown, {}};
+          AccessRanges.insert(ConstantRange(Lower, Upper));
+        }
         return {Access, AccessRanges};
       }
     }

